export const publishedInsights = insights
  .filter((insight): insight is Insight & { publishedAt: string } => insight.status === "published" && typeof insight.publishedAt === "string" && Number.isFinite(Date.parse(insight.publishedAt)))
  .sort((a, b) => Date.parse(b.publishedAt) - Date.parse(a.publishedAt));

export function getInsightBySlug(slug?: string) {
  return insights.find((insight) => insight.slug === slug);
}

export function toHeadingId(value: string) {
  return value.toLowerCase().trim().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}
